#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id (POD type, uses operator<<)
        stream << packet_id;

        // Write username with length prefix using prefixed adaptor
        stream << hexi::prefixed(username);

        // Write scores vector with count first, then elements using operator<<
        // The operator<< for iterable containers automatically writes count first
        stream << scores;

        // Write metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer (std::vector<uint8_t>)
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream object using the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Call the serialise method on the packet object with the stream
    packet.serialise(stream);

    // Return the populated buffer
    return buffer;
}
```

## Key Implementation Points:

1. **`serialise` method implementation**:
   - Uses `operator<<` for `packet_id` (POD type)
   - Uses `hexi::prefixed` adaptor for `username` to write length prefix
   - Directly uses `operator<<` for `scores` vector, which internally handles writing the count first followed by elements
   - Uses `hexi::null_terminated` adaptor for `metadata`

2. **`serialize_packet` function implementation**:
   - Creates `std::vector<uint8_t>` buffer
   - Creates `buffer_adaptor` wrapping the buffer
   - Creates `binary_stream` using the buffer adaptor
   - Calls `packet.serialise(stream)` to perform serialization
   - Returns the populated buffer

