```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    NetworkPacket packet;

    // Read packet_id using span() for zero-copy view
    auto id_span = stream.span(4);
    packet.packet_id = *reinterpret_cast<const uint32_t*>(id_span.data());

    // Read username using prefixed adaptor
    stream >> hexi::prefixed(packet.username);

    // Read scores vector using read_container
    stream >> hexi::prefixed(packet.scores);

    // Read metadata using null_terminated adaptor
    stream >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    if (stream.total_read() < buffer.size()) {
        stream.skip(buffer.size() - stream.total_read());
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    PacketInfo info;

    // Use span() to get zero-copy view of packet_id
    auto id_span = stream.span(4);
    info.packet_id = *reinterpret_cast<const uint32_t*>(id_span.data());

    // Read username using prefixed adaptor to get string_view
    std::string_view username_sv;
    stream >> hexi::prefixed(username_sv);
    info.username = username_sv;

    // Skip scores vector: read count then skip data
    std::uint32_t scores_count;
    stream >> hexi::prefixed(scores_count);
    stream.skip(scores_count * sizeof(uint32_t));

    return info;
}
```

