#include <cstdint>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Check if the requested bytes_to_preview exceed the available data in the buffer
    if (bytes_to_preview > buffer.size()) {
        // Handle error - in the original copy function, this would throw HEXI_THROW(buffer_underrun(...))
        // For this implementation, we'll return an empty vector or handle appropriately
        return std::vector<uint8_t>();
    }

    // Create a destination buffer with the required size
    std::vector<uint8_t> destination(bytes_to_preview);

    // Use the buffer's copy function to copy data without advancing the read pointer
    buffer.copy(destination.data(), bytes_to_preview);

    // Return the destination buffer containing the previewed data
    return destination;
}
```

