```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

// Global buffer for write operations
std::vector<uint8_t> g_write_buffer(1024); // Assuming 1KB buffer size

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create buffer write adaptor
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(g_write_buffer);

    std::size_t total_written = 0;

    for (const auto& chunk : chunks) {
        // Check available space before each write
        std::size_t available_space = adaptor.free();

        if (available_space == 0) {
            break; // No space left
        }

        // Write only what fits in available space
        std::size_t write_size = std::min(chunk.size(), available_space);

        if (write_size > 0) {
            adaptor.write(chunk.data(), write_size);
            total_written += write_size;
        }
    }

    return total_written;
